def forward(self, x, x_hat, likelihoods, y=None):
    bpp_loss = sum(-torch.log2(torch.clamp(l, min=1e-10)).sum() / num_pixels for l in likelihoods.values())
    d_loss = self.l1_loss(x, x_hat)
    if self.use_ms_ssim:
        d_loss += 0.5 * (1.0 - ms_ssim(self._normalize_for_ssim(x), self._normalize_for_ssim(x_hat), data_range=1.0))
    if self.use_lpips:
        d_loss += effective_weight * self.lpips_loss(x, x_hat)
    total_loss = self.lmbda * d_loss + bpp_loss + self.lmbda * reg_loss

