class STEQuantize(torch.autograd.Function):
    @staticmethod
    def forward(ctx, inputs, step_size):
        outputs = torch.round(inputs / step_size) * step_size
        return outputs

def forward(self, recon, decoder_features):
    x = torch.cat([recon, decoder_features], dim=1)
    res = self.refine_blocks(self.initial(x))
    gate = torch.sigmoid(self.residual_gate)
    return recon + gate * torch.clamp(self.final(res), -0.5, 0.5)
